# Create a minimal Express app
mkdir my-eb-app && cd my-eb-app
npm init -y
npm install express

cat > app.js << 'EOF'
const express = require('express');
const app = express();
const port = process.env.PORT || 8080;

app.get('/health', (req, res) => res.json({ status: 'ok' }));
app.get('/', (req, res) => res.send('Hello from Elastic Beanstalk'));

app.listen(port, () => console.log(`Listening on ${port}`));
EOF

# Beanstalk reads the "start" script from package.json
npm pkg set scripts.start="node app.js"

# Initialize the EB application
eb init my-eb-app \
  --platform "Node.js 20" \
  --region us-east-1

# Create the App Runner service
aws apprunner create-service \
  --service-name my-flask-api \
  --source-configuration "{
    \"ImageRepository\": {
      \"ImageIdentifier\": \"$AWS_ACCOUNT.dkr.ecr.$REGION.amazonaws.com/$REPO:latest\",
      \"ImageConfiguration\": {
        \"Port\": \"8000\"
      },
      \"ImageRepositoryType\": \"ECR\"
    },
    \"AutoDeploymentsEnabled\": true
  }" \
  --instance-configuration "{
    \"Cpu\": \"1024\",
    \"Memory\": \"2048\"
  }" \
  --region $REGION

# App Runner returns an HTTPS URL in the response (ServiceUrl field)
# Auto-deploys trigger on every new ECR image push when AutoDeploymentsEnabled=true
